const text = await space.api.fileRead("~/contacts.yaml", "utf8")
const parsed = space.utils.yaml.parse(text)

function updateMrKowalski(node) {
  if (Array.isArray(node)) {
    return node.map(updateMrKowalski)
  }
  if (node && typeof node === "object") {
    const out = {}
    for (const [key, value] of Object.entries(node)) {
      if (key === "mr_kowalski") {
        out[key] = "John Ronald Kowalski"
      } else {
        out[key] = updateMrKowalski(value)
      }
    }
    return out
  }
  return node
}

const updated = updateMrKowalski(parsed)
return await space.api.fileWrite("~/contacts.yaml", space.utils.yaml.stringify(updated), "utf8")

